        const queueDocId = runOfShowLiveItem.preparedQueueSongId || buildRunOfShowQueueDocId(roomCode, runOfShowLiveItem.id);
        if (queueDocId && lastPerformanceId && lastPerformanceId !== queueDocId) return;
