            await callFunction('awardRoomPoints', { roomCode, awards: [{ uid: targetUid, points: amount }] });
            await logActivity(roomCode, target?.name || 'Guest', `received ${amount} pts from ${hostName || 'Host'}`, EMOJI.sparkle);
            toast(`Gifted ${amount} pts`);
