                    setBgVolume={setBgVolume}
                    toggleBgMusic={toggleBgMusic}
                    playingBg={playingBg}
                    skipBg={skipBg}
                    autoBgMusic={autoBgMusic}
                    setAutoBgMusic={setAutoBgMusic}
                    autoPlayMedia={autoPlayMedia}
                    setAutoPlayMedia={setAutoPlayMedia}
